55	const PROCESSING_FEE = 5;
56	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
57	  sword: 100,
58	  amulet: 60,
59	  staff: 80,
60	  potion: 40,
61	  rune: 25,
62	};
63	
64	const basePremium = (item: Item): number =>
65	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
66	
67	const quotePremium = (items: Item[]): number =>
68	  items.reduce((sum, item) => sum + basePremium(item), 0) + PROCESSING_FEE;
69	
70	export const processScenario = (scenario: Scenario): ScenarioOutput => {
71	  const step = scenario.steps[0] as QuoteStep;
72	  return { results: [{ premium: quotePremium(step.items) }] };
73	};
